    92→/**
    93→ * Seed built-in capabilities on activation.
    94→ */
    95→function agentpress_seed_capabilities() {
    96→    $capabilities = array(
    97→        array(
    98→            'slug' => 'content_writer',
    99→            'title' => 'Content Writer',
   100→            'description' => 'Generates written content using Claude API.',
   101→        ),
   102→        array(
   103→            'slug' => 'image_generator',
   104→            'title' => 'Image Generator',
   105→            'description' => 'Generates images using Cloudflare Workers AI.',
   106→        ),
   107→    );
   108→
   109→    foreach ($capabilities as $cap) {
   110→        // Check if capability already exists
   111→        $existing = get_posts(array(
   112→            'post_type' => 'agentpress_capability',
   113→            'name' => $cap['slug'],
   114→            'posts_per_page' => 1,
   115→            'post_status' => 'any',
   116→        ));
   117→
   118→        if (empty($existing)) {
   119→            wp_insert_post(array(
   120→                'post_type' => 'agentpress_capability',
   121→                'post_title' => $cap['title'],
   122→                'post_name' => $cap['slug'],
   123→                'post_status' => 'publish',
   124→                'meta_input' => array(
   125→                    '_capability_slug' => $cap['slug'],
   126→                    '_capability_description' => $cap['description'],
   127→                ),
   128→            ));
   129→        }
   130→    }
   131→}
   132→
   133→/**
   134→ * Create default settings option.
   135→ */
   136→function agentpress_create_default_settings() {
   137→    $default_settings = array(
   138→        'default_model' => 'claude-3-5-sonnet-20241022',
   139→        'claude_api_key' => '',
   140→        'cf_worker_url' => '',
   141→    );
   142→
   143→    if (get_option('agentpress_settings') === false) {
   144→        add_option('agentpress_settings', $default_settings);
   145→    }
   146→}
   147→
   148→/**
   149→ * Plugin activation hook.
   150→ */
   151→function agentpress_activate() {
   152→    // Register CPTs so we can create posts
   153→    agentpress_register_cpts();
   154→
   155→    // Flush rewrite rules
   156→    flush_rewrite_rules();
   157→
   158→    // Seed built-in capabilities
   159→    agentpress_seed_capabilities();
   160→
   161→    // Create default settings
   162→    agentpress_create_default_settings();
   163→}
   164→register_activation_hook(__FILE__, 'agentpress_activate');
   165→
   166→/**
   167→ * Plugin deactivation hook.
   168→ */
   169→function agentpress_deactivate() {
   170→    // Flush rewrite rules on deactivation
   171→    flush_rewrite_rules();
   172→}
   173→register_deactivation_hook(__FILE__, 'agentpress_deactivate');
   174→
   175→/**
   176→ * Autoloader for AgentPress classes.
   177→ *
   178→ * @param string $class Class name to load.
   179→ */
   180→function agentpress_autoloader($class) {
   181→    // Only handle AgentPress namespace
   182→    if (strpos($class, 'AgentPress\\') !== 0) {
   183→        return;
   184→    }
   185→
   186→    // Remove namespace prefix
   187→    $class_name = str_replace('AgentPress\\', '', $class);
   188→
   189→    // Define class file mappings
   190→    $class_map = array(
   191→        'Parser' => 'includes/class-parser.php',
   192→        'Agents' => 'includes/class-agents.php',
   193→        'Logger' => 'includes/class-logger.php',
   194→        'Router' => 'includes/class-router.php',
   195→        'REST_API' => 'includes/class-rest-api.php',
   196→        'Admin' => 'admin/class-admin.php',
   197→        'Content_Writer' => 'includes/agents/class-content-writer.php',
   198→        'Image_Generator' => 'includes/agents/class-image-generator.php',
   199→    );
   200→
   201→    // Handle sub-namespaces like AgentPress\Agents\Content_Writer
   202→    if (strpos($class_name, '\\') !== false) {
   203→        $parts = explode('\\', $class_name);
   204→        $sub_namespace = strtolower($parts[0]);
   205→        $class_name = $parts[1];
   206→
   207→        $file = AGENTPRESS_PLUGIN_DIR . 'includes/' . $sub_namespace . '/class-' . strtolower(str_replace('_', '-', $class_name)) . '.php';
   208→    } else {
   209→        $file = AGENTPRESS_PLUGIN_DIR . (isset($class_map[$class_name]) ? $class_map[$class_name] : '');
   210→    }
   211→
   212→    if (file_exists($file)) {
   213→        require_once $file;
   214→    }
   215→}
   216→spl_autoload_register('agentpress_autoloader');
   217→
   218→/**
   219→ * Initialize core classes on plugins_loaded.
   220→ */
   221→function agentpress_init() {
   222→    // Initialize REST API
   223→    if (class_exists('AgentPress\\REST_API')) {
   224→        new AgentPress\REST_API();
   225→    }
   226→
   227→    // Initialize Admin
   228→    if (is_admin() && class_exists('AgentPress\\Admin')) {
   229→        new AgentPress\Admin();
   230→    }
   231→}
   232→add_action('plugins_loaded', 'agentpress_init');
   233→
   234→/**
   235→ * Register REST API routes.
   236→ */
   237→function agentpress_register_rest_routes() {
   238→    if (class_exists('AgentPress\\REST_API')) {
   239→        AgentPress\REST_API::register_routes();
   240→    }
   241→}
   242→add_action('rest_api_init', 'agentpress_register_rest_routes');
